// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  city: string; // City name
  temperature: number; // Current temperature
  condition: string; // Weather condition (Sunny, Cloudy, Rainy, etc.)
  humidity: number; // Humidity percentage
  windSpeed: number; // Wind speed
  unit: string; // Temperature unit (C or F)
  forecast: Array<{ day?: string; icon?: string; high?: number; low?: number }>; // 5-day forecast array
}





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract


  // Map weather conditions to emoji icons
  const getWeatherEmoji = (condition: string): string => {
    const conditionLower = condition.toLowerCase();
    if (conditionLower.includes('sunny') || conditionLower.includes('clear')) return '☀️';
    if (conditionLower.includes('cloudy') || conditionLower.includes('cloud')) return '☁️';
    if (conditionLower.includes('rainy') || conditionLower.includes('rain')) return '🌧️';
    if (conditionLower.includes('snow')) return '❄️';
    if (conditionLower.includes('thunder') || conditionLower.includes('storm')) return '⛈️';
    if (conditionLower.includes('windy') || conditionLower.includes('wind')) return '💨';
    if (conditionLower.includes('fog') || conditionLower.includes('mist')) return '🌫️';
    return '🌤️'; // default fallback
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Main weather card */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          <Stack gap="var(--ggui-spacing-4)">
            {/* Location header */}
            <Heading level={2} color="var(--ggui-color-onSurface)">{props.city}</Heading>

            {/* Main temperature section */}
            <Stack align="center" justify="center" gap="var(--ggui-spacing-3)">
              {/* Weather emoji/icon */}
              <Text size="4xl">{getWeatherEmoji(props.condition)}</Text>

              {/* Current temperature */}
              <Stack align="center" gap="var(--ggui-spacing-1)">
                <Text size="4xl" weight="bold" color="var(--ggui-color-primary-600)">
                  {props.temperature}°{props.unit}
                </Text>
                <Text size="xl" color="var(--ggui-color-onSurfaceVariant)">{props.condition}</Text>
              </Stack>
            </Stack>

            {/* Divider */}
            <Divider margin="var(--ggui-spacing-3)" />

            {/* Weather details grid */}
            <Row gap="var(--ggui-spacing-6)" justify="around" align="center">
              {/* Humidity */}
              <Stack align="center" gap="var(--ggui-spacing-2)">
                <Icon name="droplets" size={24} color="var(--ggui-color-primary-500)" />
                <Stack align="center" gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Humidity</Text>
                  <Text weight="semibold" color="var(--ggui-color-onSurface)">{props.humidity}%</Text>
                </Stack>
              </Stack>

              {/* Wind Speed */}
              <Stack align="center" gap="var(--ggui-spacing-2)">
                <Icon name="wind" size={24} color="var(--ggui-color-primary-500)" />
                <Stack align="center" gap="var(--ggui-spacing-1)">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Wind Speed</Text>
                  <Text weight="semibold" color="var(--ggui-color-onSurface)">{props.windSpeed} m/s</Text>
                </Stack>
              </Stack>
            </Row>
          </Stack>
        </Card>

        {/* 5-day forecast section */}
        {props.forecast && props.forecast.length > 0 && (
          <Stack gap="var(--ggui-spacing-3)">
            <Heading level={3} color="var(--ggui-color-onSurface)">5-Day Forecast</Heading>
            <Row gap="var(--ggui-spacing-3)" wrap align="stretch">
              {props.forecast.map((day, index) => (
                <Box
                  key={index}
                  padding="var(--ggui-spacing-4)"
                  background="var(--ggui-color-surfaceVariant)"
                  borderRadius="var(--ggui-shape-radius-lg)"
                  style={{ flex: '1 1 160px', minWidth: '140px', display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', gap: 'var(--ggui-spacing-2)' }}
                >
                  {/* Day name */}
                  <Text variant="label" weight="semibold" color="var(--ggui-color-onSurface)">{day.day || `Day ${index + 1}`}</Text>

                  {/* Weather icon */}
                  {day.icon ? (
                    <Text size="3xl">{day.icon}</Text>
                  ) : (
                    <Text size="3xl" color="var(--ggui-color-onSurfaceVariant)">—</Text>
                  )}

                  {/* Temperature range */}
                  <Stack align="center" gap="var(--ggui-spacing-1)">
                    {day.high !== undefined && (
                      <Text variant="body" weight="semibold" color="var(--ggui-color-onSurface)">{day.high}°</Text>
                    )}
                    {day.low !== undefined && (
                      <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{day.low}°</Text>
                    )}
                  </Stack>
                </Box>
              ))}
            </Row>
          </Stack>
        )}
      </Stack>
    </Container>
  );
}

