import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  featureOptions: string[]; // Available feature options for the checkbox step
  satisfactionLabels: string[]; // Labels for satisfaction rating (e.g., Very Unsatisfied to Very Satisfied)
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called with all collected answers as a structured object */
type ActionSubmitPayload = { name: string; email: string; satisfaction: number; features: string[]; comments: string };





// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  const submit = useAction<ActionSubmitPayload>('submit'); // Called with all collected answers as a structured object

  // State management
  const [currentStep, setCurrentStep] = useState(1);
  const [name, setName] = useState('');
  const [email, setEmail] = useState('');
  const [satisfaction, setSatisfaction] = useState('');
  const [features, setFeatures] = useState<string[]>([]);
  const [comments, setComments] = useState('');

  // Validation helpers
  const isValidEmail = (value: string): boolean => {
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    return emailRegex.test(value);
  };

  const isNameValid = name.trim().length > 0;
  const isEmailValid = email.trim().length > 0 && isValidEmail(email);
  const isStep1Valid = isNameValid && isEmailValid;
  const isStep2Valid = satisfaction !== '';
  const isStep3Valid = true; // Features step is optional

  // Determine if Next button should be enabled based on current step
  const canProceed = () => {
    switch (currentStep) {
      case 1:
        return isStep1Valid;
      case 2:
        return isStep2Valid;
      case 3:
        return isStep3Valid;
      case 4:
        return true; // Review step can always proceed to submit
      default:
        return false;
    }
  };

  const handleNext = () => {
    if (currentStep === 4) {
      // Submit the form
      submit({
        name: name.trim(),
        email: email.trim(),
        satisfaction: parseInt(satisfaction, 10),
        features,
        comments: comments.trim(),
      });
    } else {
      setCurrentStep(currentStep + 1);
    }
  };

  const handleBack = () => {
    if (currentStep > 1) {
      setCurrentStep(currentStep - 1);
    }
  };

  const toggleFeature = (feature: string) => {
    setFeatures((prev) =>
      prev.includes(feature) ? prev.filter((f) => f !== feature) : [...prev, feature]
    );
  };

  const nameError = name.trim().length === 0 && currentStep === 1 ? 'Name is required' : '';
  const emailError =
    email.trim().length === 0 && currentStep === 1
      ? 'Email is required'
      : email.trim().length > 0 && !isValidEmail(email) && currentStep === 1
      ? 'Please enter a valid email address'
      : '';

  return (
    <Container maxWidth="lg" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Progress Header */}
        <Stack gap="var(--ggui-spacing-3)">
          <Heading level={2} align="center">
            Customer Feedback Survey
          </Heading>
          <Text align="center" variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
          <Progress value={currentStep} max={4} size="md" />
        </Stack>

        {/* Step Content */}
        <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
          {currentStep === 1 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Your Information</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Please provide your name and email address.
              </Text>
              <Stack gap="var(--ggui-spacing-3)">
                <Input
                  label="Name"
                  placeholder="Enter your full name"
                  value={name}
                  onChange={setName}
                  required
                  error={nameError}
                />
                <Input
                  label="Email"
                  type="email"
                  placeholder="your@example.com"
                  value={email}
                  onChange={setEmail}
                  required
                  error={emailError}
                />
              </Stack>
            </Stack>
          )}

          {currentStep === 2 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Satisfaction Rating</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                How satisfied are you with our service?
              </Text>
              <RadioGroup
                label="Please rate your satisfaction"
                value={satisfaction}
                onChange={setSatisfaction}
                options={props.satisfactionLabels.map((label, index) => ({
                  value: String(index + 1),
                  label,
                }))}
                direction="vertical"
              />
            </Stack>
          )}

          {currentStep === 3 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Feature Interests</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Which features are you interested in? (Optional)
              </Text>
              <Stack gap="var(--ggui-spacing-2)">
                {props.featureOptions.map((feature) => (
                  <Checkbox
                    key={feature}
                    label={feature}
                    checked={features.includes(feature)}
                    onChange={() => toggleFeature(feature)}
                  />
                ))}
              </Stack>
            </Stack>
          )}

          {currentStep === 4 && (
            <Stack gap="var(--ggui-spacing-4)">
              <Heading level={3}>Review Your Answers</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Please review your answers before submitting.
              </Text>
              <Stack gap="var(--ggui-spacing-3)" direction="vertical">
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)" direction="vertical">
                    <Text variant="label" color="var(--ggui-color-primary-700)">
                      Name
                    </Text>
                    <Text variant="body">{name}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)" direction="vertical">
                    <Text variant="label" color="var(--ggui-color-primary-700)">
                      Email
                    </Text>
                    <Text variant="body">{email}</Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)" direction="vertical">
                    <Text variant="label" color="var(--ggui-color-primary-700)">
                      Satisfaction Rating
                    </Text>
                    <Text variant="body">
                      {props.satisfactionLabels[parseInt(satisfaction, 10) - 1]}
                    </Text>
                  </Stack>
                </Box>
                <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                  <Stack gap="var(--ggui-spacing-2)" direction="vertical">
                    <Text variant="label" color="var(--ggui-color-primary-700)">
                      Features of Interest
                    </Text>
                    <Text variant="body">
                      {features.length > 0 ? features.join(', ') : 'None selected'}
                    </Text>
                  </Stack>
                </Box>
                {comments && (
                  <Box padding="var(--ggui-spacing-3)" background="var(--ggui-color-primary-50)" borderRadius="var(--ggui-shape-radius-md)">
                    <Stack gap="var(--ggui-spacing-2)" direction="vertical">
                      <Text variant="label" color="var(--ggui-color-primary-700)">
                        Comments
                      </Text>
                      <Text variant="body">{comments}</Text>
                    </Stack>
                  </Box>
                )}
              </Stack>
            </Stack>
          )}

          {currentStep === 4 && !comments && (
            <Alert variant="info" title="Optional Step">
              You skipped the comments section. You can still add comments or proceed to submit.
            </Alert>
          )}
        </Card>

        {/* Comments Section (shown on step 4 for editing, or separately) */}
        {currentStep === 4 && (
          <Card shadow="md" padding="var(--ggui-spacing-6)" radius="lg">
            <Stack gap="var(--ggui-spacing-3)">
              <Heading level={4}>Additional Comments</Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Any additional feedback? (Optional)
              </Text>
              <TextArea
                label="Comments"
                placeholder="Enter your comments here..."
                value={comments}
                onChange={setComments}
                rows={4}
                maxLength={500}
                showCount
              />
            </Stack>
          </Card>
        )}


        {/* Navigation Buttons */}
        <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
          <Button
            variant="outline"
            onClick={handleBack}
            disabled={currentStep === 1}
          >
            Back
          </Button>
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Step {currentStep} of 4
          </Text>
          <Button
            variant="primary"
            onClick={handleNext}
            disabled={!canProceed()}
          >
            {currentStep === 4 ? 'Submit' : 'Next'}
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

