import React, { useState, useCallback, useMemo, useEffect, useRef } from 'react';
// Layout: Container, Card, Stack, Row, Box, Divider, Spacer
// Typography: Text, Heading | Inputs: Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider
// Display: Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip | Data: Table, Tabs, Accordion
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction, useStream } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  tasks: Array<{ id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string }>; // Array of tasks with id, title, priority (low/medium/high), assignee initials, column ID, and optional dueDate
  columns: Array<{ id?: string; name?: string }>; // Column definitions: [{id: "todo", name: "To Do"}, {id: "in-progress", name: "In Progress"}, {id: "done", name: "Done"}]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when a task is moved, edited, or created. Payload: { action, taskId, data } */
type ActionTaskUpdatePayload = { action: string; taskId: string; data: { column: string } };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: A task was moved, edited, or created by another user — update it in the board */
type StreamTaskChanged = { action?: 'create' | 'move' | 'edit' | 'delete'; task?: { id?: string; title?: string; priority?: 'low' | 'medium' | 'high'; assignee?: string; column?: string; dueDate?: string } };




// Helper to get color for priority badge
const getPriorityColor = (priority?: string): 'error' | 'warning' | 'success' | 'default' => {
  switch (priority) {
    case 'high': return 'error';
    case 'medium': return 'warning';
    case 'low': return 'success';
    default: return 'default';
  }
};

// Task card component
function TaskCard({
  task,
  columns,
  onMove,
  onEdit,
}: {
  task: Props['tasks'][0];
  columns: Props['columns'];
  onMove: (taskId: string, toColumn: string) => void;
  onEdit: (taskId: string, title: string) => void;
}) {
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState(task.title || '');

  const handleDoubleClick = () => {
    setIsEditing(true);
    setEditTitle(task.title || '');
  };

  const handleSaveEdit = () => {
    if (editTitle.trim() && editTitle !== task.title) {
      onEdit(task.id || '', editTitle);
    }
    setIsEditing(false);
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSaveEdit();
    } else if (e.key === 'Escape') {
      setIsEditing(false);
    }
  };

  const otherColumns = columns.filter((col) => col.id !== task.column);

  return (
    <Card shadow="sm" padding="var(--ggui-spacing-3)" radius="md">
      <Stack gap="var(--ggui-spacing-2)">
        {isEditing ? (
          <Input
            label="Task title"
            value={editTitle}
            onChange={setEditTitle}
            onKeyDown={handleKeyDown}
            autoFocus
          />
        ) : (
          <Text
            variant="body"
            weight="medium"
            onClick={handleDoubleClick}
            as={Clickable}
            style={{ cursor: 'pointer', padding: 'var(--ggui-spacing-1)' }}
          >
            {task.title || 'Untitled'}
          </Text>
        )}

        <Row gap="var(--ggui-spacing-2)" align="center">
          {task.priority && (
            <Badge variant={getPriorityColor(task.priority)} size="sm">
              {task.priority}
            </Badge>
          )}
          {task.assignee && (
            <Avatar name={task.assignee} size="sm" />
          )}
        </Row>

        {task.dueDate && (
          <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
            Due: {new Date(task.dueDate).toLocaleDateString()}
          </Text>
        )}

        <Row gap="var(--ggui-spacing-1)" justify="end">
          {isEditing ? (
            <>
              <Button size="xs" variant="primary" onClick={handleSaveEdit}>
                Save
              </Button>
              <Button size="xs" variant="ghost" onClick={() => setIsEditing(false)}>
                Cancel
              </Button>
            </>
          ) : (
            <>
              <Button
                size="xs"
                variant="ghost"
                onClick={() => setIsEditing(true)}
              >
                Edit
              </Button>
              {otherColumns.length > 0 && (
                <Dropdown
                  trigger={<Button size="xs" variant="ghost">Move</Button>}
                  options={otherColumns.map((col) => ({
                    value: col.id || '',
                    label: col.name || 'Unknown',
                  }))}
                  value=""
                  onChange={(colId) => onMove(task.id || '', colId)}
                  placement="bottom-end"
                />
              )}
            </>
          )}
        </Row>
      </Stack>
    </Card>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const taskUpdate = useAction<ActionTaskUpdatePayload>('taskUpdate'); // Called when a task is moved, edited, or created. Payload: { action, taskId, data }

  // Streams — real-time from agent (.latest, .all)
  const taskChanged = useStream<StreamTaskChanged>('taskChanged'); // A task was moved, edited, or created by another user — update it in the board

  // State
  const [tasks, setTasks] = useState(props.tasks);
  const [addingTaskColumn, setAddingTaskColumn] = useState<string | null>(null);
  const [newTaskTitle, setNewTaskTitle] = useState('');
  const [newTaskPriority, setNewTaskPriority] = useState<'low' | 'medium' | 'high'>('medium');

  // Sync props to state
  useEffect(() => {
    setTasks(props.tasks);
  }, [props.tasks]);

  // Listen for real-time updates from stream
  useEffect(() => {
    if (taskChanged.latest) {
      const { action, task } = taskChanged.latest;
      if (action === 'create' && task) {
        setTasks((prev) => [...prev, task]);
      } else if (action === 'move' && task) {
        setTasks((prev) =>
          prev.map((t) => (t.id === task.id ? task : t))
        );
      } else if (action === 'edit' && task) {
        setTasks((prev) =>
          prev.map((t) => (t.id === task.id ? task : t))
        );
      } else if (action === 'delete' && task) {
        setTasks((prev) => prev.filter((t) => t.id !== task.id));
      }
    }
  }, [taskChanged.latest]);

  // Handlers
  const handleAddTask = () => {
    if (!newTaskTitle.trim() || !addingTaskColumn) return;

    const newTask = {
      id: `task-${Date.now()}`,
      title: newTaskTitle,
      priority: newTaskPriority,
      column: addingTaskColumn,
    };

    setTasks((prev) => [...prev, newTask]);
    taskUpdate({
      action: 'create',
      taskId: newTask.id,
      data: { column: addingTaskColumn },
    });

    setNewTaskTitle('');
    setNewTaskPriority('medium');
    setAddingTaskColumn(null);
  };

  const handleMoveTask = (taskId: string, toColumn: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: toColumn } : t))
    );
    taskUpdate({
      action: 'move',
      taskId,
      data: { column: toColumn },
    });
  };

  const handleEditTask = (taskId: string, newTitle: string) => {
    setTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, title: newTitle } : t))
    );
    taskUpdate({
      action: 'edit',
      taskId,
      data: { column: tasks.find((t) => t.id === taskId)?.column || 'todo' },
    });
  };

  // Compute stats
  const totalTasks = tasks.length;
  const completedTasks = tasks.filter((t) => t.column === 'done').length;

  // Group tasks by column
  const tasksByColumn = useMemo(() => {
    return props.columns.reduce(
      (acc, col) => {
        acc[col.id || ''] = tasks.filter((t) => t.column === col.id);
        return acc;
      },
      {} as Record<string, typeof tasks>
    );
  }, [tasks, props.columns]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Summary Bar */}
        <Box
          padding="var(--ggui-spacing-4)"
          background="var(--ggui-color-primary-50)"
          borderRadius="var(--ggui-shape-radius-lg)"
        >
          <Row justify="between" align="center">
            <Stack gap="var(--ggui-spacing-2)">
              <Text variant="label" color="var(--ggui-color-primary-700)">
                Task Summary
              </Text>
              <Row gap="var(--ggui-spacing-4)" align="center">
                <Text color="var(--ggui-color-onSurface)">
                  Total: <Text as="span" weight="bold">{totalTasks}</Text>
                </Text>
                <Divider orientation="vertical" margin="0" />
                <Text color="var(--ggui-color-onSurface)">
                  Completed: <Text as="span" weight="bold" color="var(--ggui-color-success-600)">{completedTasks}</Text>
                </Text>
              </Row>
            </Stack>
            <Progress value={totalTasks > 0 ? (completedTasks / totalTasks) * 100 : 0} max={100} size="md" />
          </Row>
        </Box>

        {/* Kanban Board */}
        <Row gap="var(--ggui-spacing-4)" align="start" style={{ flex: 1, flexWrap: 'wrap' }}>
          {props.columns.map((column) => (
            <Stack
              key={column.id}
              gap="var(--ggui-spacing-3)"
              style={{
                flex: '1 1 300px',
                maxWidth: '400px',
              }}
            >
              {/* Column Header */}
              <Box
                padding="var(--ggui-spacing-3)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-md)"
              >
                <Row justify="between" align="center">
                  <Stack gap="var(--ggui-spacing-1)">
                    <Heading level={4}>{column.name}</Heading>
                    <Badge variant="secondary" size="sm">
                      {tasksByColumn[column.id || '']?.length || 0}
                    </Badge>
                  </Stack>
                </Row>
              </Box>

              {/* Task List */}
              <Stack gap="var(--ggui-spacing-2)" style={{ minHeight: '200px' }}>
                {(tasksByColumn[column.id || ''] || []).map((task) => (
                  <TaskCard
                    key={task.id}
                    task={task}
                    columns={props.columns}
                    onMove={handleMoveTask}
                    onEdit={handleEditTask}
                  />
                ))}
              </Stack>

              {/* Add Task Section */}
              {addingTaskColumn === column.id ? (
                <Card shadow="sm" padding="var(--ggui-spacing-3)" radius="md">
                  <Stack gap="var(--ggui-spacing-2)">
                    <Input
                      label="Task title"
                      placeholder="Enter task title"
                      value={newTaskTitle}
                      onChange={setNewTaskTitle}
                      autoFocus
                    />
                    <Select
                      label="Priority"
                      value={newTaskPriority}
                      onChange={(val) => setNewTaskPriority(val as 'low' | 'medium' | 'high')}
                      options={[
                        { value: 'low', label: 'Low' },
                        { value: 'medium', label: 'Medium' },
                        { value: 'high', label: 'High' },
                      ]}
                    />
                    <Row gap="var(--ggui-spacing-2)" justify="end">
                      <Button
                        size="sm"
                        variant="ghost"
                        onClick={() => {
                          setAddingTaskColumn(null);
                          setNewTaskTitle('');
                          setNewTaskPriority('medium');
                        }}
                      >
                        Cancel
                      </Button>
                      <Button
                        size="sm"
                        variant="primary"
                        onClick={handleAddTask}
                      >
                        Add Task
                      </Button>
                    </Row>
                  </Stack>
                </Card>
              ) : (
                <Button
                  size="md"
                  variant="outline"
                  fullWidth
                  onClick={() => {
                    setAddingTaskColumn(column.id || null);
                    setNewTaskTitle('');
                    setNewTaskPriority('medium');
                  }}
                >
                  + Add Task
                </Button>
              )}
            </Stack>
          ))}
        </Row>
      </Stack>
    </Container>
  );
}

