interface Props {
  elements: Array<{ atomicNumber?: number; symbol?: string; name?: string; atomicWeight?: number; category?: string; row?: number; col?: number }>; // Full periodic table element data
}





// Category to color mapping — using design tokens for theming
const CATEGORY_COLORS: Record<string, { bg: string; text: string }> = {
  'alkali metal': { bg: 'var(--ggui-color-primary-100)', text: 'var(--ggui-color-primary-700)' },
  'alkaline earth metal': { bg: 'var(--ggui-color-info-100)', text: 'var(--ggui-color-info-700)' },
  'transition metal': { bg: 'var(--ggui-color-warning-100)', text: 'var(--ggui-color-warning-700)' },
  'post-transition metal': { bg: 'var(--ggui-color-success-100)', text: 'var(--ggui-color-success-700)' },
  'metalloid': { bg: 'var(--ggui-color-error-100)', text: 'var(--ggui-color-error-700)' },
  'nonmetal': { bg: '#fff4e6', text: '#d97706' },
  'halogen': { bg: '#fecaca', text: '#dc2626' },
  'noble gas': { bg: '#dbeafe', text: '#1e40af' },
};

export default function Component(props: Props) {
  const [searchQuery, setSearchQuery] = useState('');
  const [selectedElement, setSelectedElement] = useState<(typeof props.elements)[0] | null>(null);

  // Filter elements by name or symbol
  const filteredElements = useMemo(() => {
    if (!searchQuery.trim()) return props.elements;
    const lowerQuery = searchQuery.toLowerCase();
    return props.elements.filter((el) =>
      (el.name?.toLowerCase().includes(lowerQuery) || el.symbol?.toLowerCase().includes(lowerQuery))
    );
  }, [searchQuery, props.elements]);

  // Get unique categories and sort them for the legend
  const uniqueCategories = useMemo(() => {
    const cats = new Set(props.elements.map((el) => el.category).filter(Boolean));
    return Array.from(cats).sort();
  }, [props.elements]);

  // Get color for a category with fallback
  const getCategoryColor = (category?: string) => {
    if (!category) return { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurfaceVariant)' };
    return CATEGORY_COLORS[category.toLowerCase()] || { bg: 'var(--ggui-color-surfaceVariant)', text: 'var(--ggui-color-onSurfaceVariant)' };
  };

  return (
    <Container maxWidth="100%" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        {/* Header */}
        <Stack gap="var(--ggui-spacing-2)">
          <Heading level={1}>Periodic Table of Elements</Heading>
          <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
            Explore the elements by searching for name or symbol. Click any element for details.
          </Text>
        </Stack>

        {/* Search input */}
        <Input
          label="Search by name or symbol"
          placeholder="e.g., Gold or Au"
          value={searchQuery}
          onChange={setSearchQuery}
          size="md"
        />

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" border shadow="sm">
          <Stack gap="var(--ggui-spacing-3)">
            <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">Category Legend</Text>
            <Row gap="var(--ggui-spacing-4)" wrap>
              {uniqueCategories.map((category) => {
                const colors = getCategoryColor(category);
                return (
                  <Row key={category} align="center" gap="var(--ggui-spacing-2)">
                    <Box
                      background={colors.bg}
                      padding="var(--ggui-spacing-1)"
                      borderRadius="var(--ggui-shape-radius-sm)"
                      style={{ width: '20px', height: '20px' }}
                    />
                    <Text variant="bodySmall" color={colors.text}>
                      {category}
                    </Text>
                  </Row>
                );
              })}
            </Row>
          </Stack>
        </Card>

        {/* Periodic Table Grid */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-2)',
            padding: 'var(--ggui-spacing-4)',
            background: 'var(--ggui-color-surfaceVariant)',
            borderRadius: 'var(--ggui-shape-radius-lg)',
          }}
        >
          {filteredElements.map((element) => {
            const colors = getCategoryColor(element.category);
            const isSelected = selectedElement?.symbol === element.symbol;
            return (
              <Box
                key={`${element.atomicNumber}-${element.symbol}`}
                as={Clickable}
                onClick={() => setSelectedElement(element)}
                style={{
                  gridColumn: `${element.col || 1}`,
                  gridRow: `${element.row || 1}`,
                  background: colors.bg,
                  border: isSelected ? '3px solid var(--ggui-color-primary-600)' : '1px solid var(--ggui-color-outline)',
                  borderRadius: 'var(--ggui-shape-radius-md)',
                  padding: 'var(--ggui-spacing-2)',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  cursor: 'pointer',
                  minHeight: '80px',
                  textAlign: 'center',
                  transition: 'all 200ms ease-in-out',
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'var(--ggui-shape-shadow-sm)',
                  transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                }}
                hoverStyle={{
                  opacity: 0.9,
                  transform: 'scale(1.03)',
                }}
              >
                <Text
                  variant="caption"
                  color={colors.text}
                  style={{ fontSize: 'var(--ggui-font-size-xs)', marginBottom: '4px' }}
                >
                  {element.atomicNumber}
                </Text>
                <Text
                  variant="label"
                  color={colors.text}
                  style={{ fontSize: '20px', fontWeight: 'var(--ggui-font-weight-bold)' }}
                >
                  {element.symbol}
                </Text>
              </Box>
            );
          })}        </Box>

        {/* Details Panel */}
        {selectedElement && (
          <Card padding="var(--ggui-spacing-4)" shadow="md" border>
            <Stack gap="var(--ggui-spacing-3)">
              <Row align="center" justify="between">
                <Heading level={2}>{selectedElement.name}</Heading>
                <Button
                  variant="ghost"
                  size="sm"
                  onClick={() => setSelectedElement(null)}
                >
                  ×
                </Button>
              </Row>

              <Divider />

              <Stack gap="var(--ggui-spacing-2)">
                <Row justify="between" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Symbol
                  </Text>
                  <Text variant="body" weight="semibold">
                    {selectedElement.symbol}
                  </Text>
                </Row>

                <Row justify="between" align="center">
                  <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                    Atomic Number
                  </Text>
                  <Text variant="body" weight="semibold">
                    {selectedElement.atomicNumber}
                  </Text>
                </Row>

                {selectedElement.atomicWeight && (
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Weight
                    </Text>
                    <Text variant="body" weight="semibold">
                      {selectedElement.atomicWeight.toFixed(3)}
                    </Text>
                  </Row>
                )}

                {selectedElement.category && (
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Category
                    </Text>
                    <Badge
                      variant="primary"
                      size="md"
                      style={{
                        background: getCategoryColor(selectedElement.category).bg,
                        color: getCategoryColor(selectedElement.category).text,
                      }}
                    >
                      {selectedElement.category}
                    </Badge>
                  </Row>
                )}

                {selectedElement.row && selectedElement.col && (
                  <Row justify="between" align="center">
                    <Text variant="label" color="var(--ggui-color-onSurfaceVariant)">
                      Position
                    </Text>
                    <Text variant="body" weight="semibold">
                      Row {selectedElement.row}, Column {selectedElement.col}
                    </Text>
                  </Row>
                )}
              </Stack>
            </Stack>
          </Card>
        )}

        {/* Empty state when search yields no results */}
        {filteredElements.length === 0 && (
          <Alert variant="info" title="No elements found">
            Try searching for a different element name or symbol.
          </Alert>
        )}
      </Stack>
    </Container>
  );
}

