import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
// Components: SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';
// Compositions: Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, Modal, Footer, Hero
import { Header, Sidebar, CardGrid, CommentThread, DataTable, ChatWindow, NavigationBar, FileUploader, UserProfileCard, NotificationCenter, Modal, CommandPalette, Footer, Hero } from '@ggui-ai/design/compositions';
// Interaction wrappers: use as={Clickable} on primitives for onClick, as={Hoverable} for hover, as={Pressable} for press
import { Clickable, Hoverable, Pressable } from '@ggui-ai/design/interact';
import { useAction } from '@ggui-ai/wire';
// prettier-ignore-end

// DO NOT EDIT Props — auto-generated from the data contract
// DO NOT EDIT — generated from data contract. Changing this will fail validation.
interface Props {
  product: { id?: string; name?: string; price?: number; currency?: string; rating?: number; reviewCount?: number; stock?: number; description?: string; specifications?: unknown[]; reviews?: unknown[] }; // Product object with id, name, price, currency, rating, stock, description, specifications[], reviews[]
}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user clicks Add to Cart. Payload: { productId, quantity } */
type ActionAddToCartPayload = { productId: string; quantity: number };





// Helper component to render rating stars
function RatingStars({ rating, size = 16 }: { rating?: number; size?: number }) {
  if (!rating) return null;
  const fullStars = Math.floor(rating);
  const hasHalf = rating % 1 !== 0;
  const emptyStars = 5 - Math.ceil(rating);
  return (
    <Row gap="var(--ggui-spacing-1)" align="center">
      {Array.from({ length: fullStars }).map((_, i) => (
        <Icon key={`full-${i}`} name="star" size={size} color="var(--ggui-color-warning-500)" />
      ))}
      {hasHalf && <Icon name="star-half-2" size={size} color="var(--ggui-color-warning-500)" />}
      {Array.from({ length: emptyStars }).map((_, i) => (
        <Icon key={`empty-${i}`} name="star" size={size} color="var(--ggui-color-outline)" />
      ))}
    </Row>
  );
}


export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
  // Actions — fire-and-forget to agent
  const addToCart = useAction<ActionAddToCartPayload>('addToCart'); // Called when user clicks Add to Cart. Payload: { productId, quantity }

  // State for quantity selector and active tab
  const [quantity, setQuantity] = useState(1);
  const [activeTab, setActiveTab] = useState('description');

  // Guard against missing product data
  if (!props.product || !props.product.id) {
    return <Container><Text>Product not found</Text></Container>;
  }

  const product = props.product;
  const isOutOfStock = !product.stock || product.stock <= 0;
  const isLowStock = product.stock && product.stock > 0 && product.stock < 5;

  // Handle Add to Cart
  const handleAddToCart = useCallback(() => {
    if (product.id) {
      addToCart({ productId: product.id, quantity });
      setQuantity(1);
    }
  }, [product.id, quantity, addToCart]);

  // Handle quantity changes
  const handleQuantityChange = useCallback((newQty: number) => {
    const max = product.stock || 1;
    const clamped = Math.max(1, Math.min(newQty, max));
    setQuantity(clamped);
  }, [product.stock]);

  // Format price with currency
  const formattedPrice = product.price
    ? `${product.currency || '$'}${product.price.toFixed(2)}`
    : 'N/A';

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Top Section: Image & Product Info */}
        <Row gap="var(--ggui-spacing-6)" align="start" wrap>
          {/* Product Image Placeholder */}
          <Box
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
            padding="var(--ggui-spacing-8)"
            style={{ minWidth: '300px', minHeight: '400px', display: 'flex', alignItems: 'center', justifyContent: 'center' }}
          >
            <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
              <Icon name="image" size={48} color="var(--ggui-color-onSurfaceVariant)" />
              <Text color="var(--ggui-color-onSurfaceVariant)" align="center">{product.name}</Text>
            </Stack>
          </Box>

          {/* Product Details */}
          <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1, minWidth: '300px' }}>
            <Heading level={1}>{product.name}</Heading>

            {/* Price & Rating Row */}
            <Row gap="var(--ggui-spacing-4)" align="center">
              <Text size="2xl" weight="bold" color="var(--ggui-color-primary-600)">
                {formattedPrice}
              </Text>
              {product.rating && (
                <Row gap="var(--ggui-spacing-2)" align="center">
                  <RatingStars rating={product.rating} size={20} />
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    ({product.reviewCount || 0})
                  </Text>
                </Row>
              )}
            </Row>

            {/* Stock Status Badge */}
            {isOutOfStock ? (
              <Badge variant="error">Out of Stock</Badge>
            ) : isLowStock ? (
              <Badge variant="warning">Low Stock</Badge>
            ) : (
              <Badge variant="success">In Stock</Badge>
            )}
          </Stack>
        </Row>

        {/* Middle Section: Tabs */}
        <Tabs
          variant="line"
          items={[
            {
              key: 'description',
              label: 'Description',
              content: (
                <Box paddingY="var(--ggui-spacing-4)">
                  <Stack gap="var(--ggui-spacing-3)">
                    <Text>{product.description || 'No description available'}</Text>
                  </Stack>
                </Box>
              ),
            },
            {
              key: 'specifications',
              label: 'Specifications',
              content: (
                <Box padding="var(--ggui-spacing-4) 0">
                  {Array.isArray(product.specifications) && product.specifications.length > 0 ? (
                    <Table
                      columns={[
                        { key: 'key', header: 'Property', width: '40%' },
                        { key: 'value', header: 'Value', width: '60%' },
                      ]}
                      data={product.specifications.map((spec: unknown) => {
                        const s = spec as { key?: string; value?: string };
                        return { key: s.key || '', value: s.value || '' };
                      })}
                      compact
                    />
                  ) : (
                    <Text color="var(--ggui-color-onSurfaceVariant)">No specifications available</Text>
                  )}
                </Box>
              ),
            },
            {
              key: 'reviews',
              label: 'Reviews',
              content: (
                <Box paddingY="var(--ggui-spacing-4)">
                  <Stack gap="var(--ggui-spacing-3)">
                    {Array.isArray(product.reviews) && product.reviews.length > 0 ? (
                      product.reviews.map((review: unknown, idx: number) => {
                        const r = review as { author?: string; rating?: number; text?: string; date?: string };
                        return (
                          <Card key={idx} padding="var(--ggui-spacing-3)" shadow="sm">
                            <Stack gap="var(--ggui-spacing-2)">
                              <Row gap="var(--ggui-spacing-2)" align="center" justify="between">
                                <Text weight="semibold">{r.author || 'Anonymous'}</Text>
                                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">{r.date || 'Unknown date'}</Text>
                              </Row>
                              {r.rating && <RatingStars rating={r.rating} size={16} />}
                              <Text>{r.text || ''}</Text>
                            </Stack>
                          </Card>
                        );
                      })
                    ) : (
                      <Text color="var(--ggui-color-onSurfaceVariant)">No reviews yet</Text>
                    )}
                  </Stack>
                </Box>
            },
          ]}
          activeKey={activeTab}
          onChange={setActiveTab}
        />

        {/* Bottom Section: Quantity & Add to Cart */}
        <Stack gap="var(--ggui-spacing-4)" direction="horizontal" align="center">
          {/* Quantity Selector */}
          <Row gap="var(--ggui-spacing-2)" align="center">
            <Text variant="label">Quantity:</Text>
            <Button
              size="sm"
              variant="outline"
              onClick={() => handleQuantityChange(quantity - 1)}
              disabled={quantity <= 1}
            >
              −
            </Button>
            <Text variant="label" style={{ minWidth: '40px', textAlign: 'center' }}>
              {quantity}
            </Text>
            <Button
              size="sm"
              variant="outline"
              onClick={() => handleQuantityChange(quantity + 1)}
              disabled={quantity >= (product.stock || 1)}
            >
              +
            </Button>
          </Row>

          {/* Add to Cart Button */}
          <Button
            variant="primary"
            size="lg"
            onClick={handleAddToCart}
            disabled={isOutOfStock}
          >
            Add to Cart
          </Button>
        </Stack>
      </Stack>
    </Container>
