}

// DO NOT EDIT — action payload types generated from action contract.
/** Action payload: Called when user sends a message. Payload: { text, timestamp } */
type ActionSendMessagePayload = { text: string; timestamp: string };


// DO NOT EDIT — stream event types generated from stream contract.
/** Stream event: New message from another participant — append to message list */
type StreamMessage = { sender?: string; text?: string; timestamp?: string };

/** Stream event: Typing indicator — show/hide based on active flag */
type StreamTyping = { sender?: string; active?: boolean };




// Place helper components here if needed

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract
    // Actions — fire-and-forget to agent
  const sendMessage = useAction<ActionSendMessagePayload>('sendMessage'); // Called when user sends a message. Payload: { text, timestamp }

  // Streams — real-time from agent (.latest, .all)
  const message = useStream<StreamMessage>('message'); // New message from another participant — append to message list
  const typing = useStream<StreamTyping>('typing'); // Typing indicator — show/hide based on active flag

  // State management
  const [messageText, setMessageText] = useState('');
  const [allMessages, setAllMessages] = useState(props.messages || []);
  const [typingUser, setTypingUser] = useState<{ sender?: string } | null>(null);
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Auto-scroll to bottom when new messages arrive
  const scrollToBottom = useCallback(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, []);

  useEffect(() => {
    scrollToBottom();
  }, [allMessages, scrollToBottom]);

  // Append new messages from stream
  useEffect(() => {
    if (message.latest) {
      setAllMessages((prev) => [...prev, message.latest]);
    }
  }, [message.latest]);

  // Handle typing indicator
  useEffect(() => {
    if (typing.latest) {
      if (typing.latest.active && typing.latest.sender !== props.currentUser) {
        setTypingUser(typing.latest);
      } else {
        setTypingUser(null);
      }
    }
  }, [typing.latest, props.currentUser]);

  // Handle send message
  const handleSendMessage = useCallback(() => {
    if (messageText.trim()) {
      const timestamp = new Date().toISOString();
      sendMessage({ text: messageText, timestamp });
      setMessageText('');
    }
  }, [messageText, sendMessage]);

  // Handle Enter key to send
  const handleKeyDown = useCallback(
    (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
      if (e.key === 'Enter' && !e.shiftKey) {
        e.preventDefault();
        handleSendMessage();
      }
    },
    [handleSendMessage]
  );

  // Group consecutive messages from same sender
  const groupedMessages = useMemo(() => {
    const groups: Array<{
      sender?: string;
      messages: Array<{ sender?: string; text?: string; timestamp?: string }>;
    }> = [];

    for (const msg of allMessages) {
      const lastGroup = groups[groups.length - 1];
      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        groups.push({ sender: msg.sender, messages: [msg] });
      }
    }
    return groups;
  }, [allMessages]);

  // Format timestamp to HH:MM AM/PM
  const formatTime = (timestamp?: string) => {
    if (!timestamp) return '';
    const date = new Date(timestamp);
    return date.toLocaleTimeString('en-US', {
      hour: 'numeric',
      minute: '2-digit',
      hour12: true,
    });
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-4)" style={{ height: '100vh', maxHeight: '100vh' }}>
        {/* Header */}
        <Card padding="var(--ggui-spacing-4)" shadow="sm">
          <Row justify="between" align="center" gap="var(--ggui-spacing-4)">
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={3}>{props.title}</Heading>
            </Stack>
            <Badge variant="primary">{props.participantCount} participants</Badge>
          </Row>
        </Card>

        {/* Messages container */}
        <Card
          padding="var(--ggui-spacing-4)"
          shadow="sm"
          style={{
            flex: 1,
            overflowY: 'auto',
            display: 'flex',
            flexDirection: 'column',
            gap: 'var(--ggui-spacing-3)',
          }}
        >
          {groupedMessages.map((group, groupIdx) => {
            const isCurrentUser = group.sender === props.currentUser;
            return (
              <Stack
                key={groupIdx}
                align={isCurrentUser ? 'end' : 'start'}
                gap="var(--ggui-spacing-2)"
              >
                {group.messages.map((msg, msgIdx) => (
                  <Box
                    key={msgIdx}
                    padding="var(--ggui-spacing-3)"
                    background={
                      isCurrentUser
                        ? 'var(--ggui-color-primary-600)'
                        : 'var(--ggui-color-surfaceVariant)'
                    }
                    borderRadius="var(--ggui-shape-radius-lg)"
                    style={{
                      maxWidth: '60%',
                      wordWrap: 'break-word',
                    }}
                  >
                    {!isCurrentUser && group.sender && (
                      <Text
                        variant="label"
                        color="var(--ggui-color-onSurfaceVariant)"
                        style={{ marginBottom: 'var(--ggui-spacing-1)' }}
                      >
                        {group.sender}
                      </Text>
                    )}
                    <Text
                      color={
                        isCurrentUser
                          ? 'white'
                          : 'var(--ggui-color-onSurface)'
                      }
                    >
                      {msg.text}
                    </Text>
                    <Text
                      variant="caption"
                      color={
                        isCurrentUser
                          ? 'rgba(255,255,255,0.7)'
                          : 'var(--ggui-color-onSurfaceVariant)'
                      }
                      style={{ marginTop: 'var(--ggui-spacing-1)' }}
                    >
                      {formatTime(msg.timestamp)}
                    </Text>
                  </Box>
                ))}
              </Stack>
            );
          })}

          {/* Typing indicator */}
          {typingUser && (
            <Stack align="start" gap="var(--ggui-spacing-2)">
              <Box
                padding="var(--ggui-spacing-3)"
                background="var(--ggui-color-surfaceVariant)"
                borderRadius="var(--ggui-shape-radius-lg)"
              >
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  {typingUser.sender} is typing
                  <span style={{ animation: 'ggui-pulse 1s ease-in-out infinite' }}>
                    ....
                  </span>
                </Text>
              </Box>
            </Stack>
          )}

          {/* Scroll anchor */}
          <div ref={messagesEndRef} />
        </Card>

        {/* Input area */}
        <Row gap="var(--ggui-spacing-2)" align="end">
          <TextArea
            label="Message"
            placeholder="Type your message...(Shift+Enter for newline)"
            value={messageText}
            onChange={setMessageText}
            onKeyDown={handleKeyDown}
            rows={2}
            style={{ flex: 1 }}
          />
          <Button
            variant="primary"
            onClick={handleSendMessage}
            disabled={!messageText.trim()}
          >
            Send
          </Button>
        </Row>
      </Stack>
    </Container>
  );
}

