export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  // State for merged stock data and tracking updates
  const [stocks, setStocks] = useState(props.stocks);
  const [lastUpdated, setLastUpdated] = useState<string>('');
  const [updatingSymbols, setUpdatingSymbols] = useState<Set<string>>(new Set());
  const updateTimeoutRef = useRef<Map<string, NodeJS.Timeout>>(new Map());

  // Update stocks when price updates arrive from stream
  useEffect(() => {
    if (priceUpdate.latest) {
      const update = priceUpdate.latest;
      setStocks((prevStocks) => {
        return prevStocks.map((stock) => {
          if (stock.symbol === update.symbol) {
            return {
              ...stock,
              price: update.price ?? stock.price,
              change: update.change ?? stock.change,
              changePercent: update.changePercent ?? stock.changePercent,
            };
          }
          return stock;
        });
      });

      // Track this symbol as updating for animation
      if (update.symbol) {
        setUpdatingSymbols((prev) => new Set(prev).add(update.symbol));

        // Clear existing timeout if any
        if (updateTimeoutRef.current.has(update.symbol)) {
          clearTimeout(updateTimeoutRef.current.get(update.symbol)!);
        }

        // Set new timeout to remove the updating indicator after animation completes
        const timeoutId = setTimeout(() => {
          setUpdatingSymbols((prev) => {
            const next = new Set(prev);
            next.delete(update.symbol!);
            return next;
          });
          updateTimeoutRef.current.delete(update.symbol);
        }, 600); // Match animation duration

        updateTimeoutRef.current.set(update.symbol, timeoutId);
      }

      // Update last updated timestamp
      setLastUpdated(new Date().toLocaleString());
    }
  }, [priceUpdate.latest]);

  // Cleanup timeouts on unmount
  useEffect(() => {
    return () => {
      updateTimeoutRef.current.forEach((timeoutId) => clearTimeout(timeoutId));
    };
  }, []);

  // Get market status from stream
  const marketIsOpen = marketStatus.latest?.status === 'open';
  const statusBadgeVariant = marketIsOpen ? 'success' : 'warning';
  const statusText = marketStatus.latest?.status ? marketStatus.latest.status.charAt(0).toUpperCase() + marketStatus.latest.status.slice(1).replace('-', ' ') : 'Unknown';

  return (
    <Container maxWidth="2xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)" align="stretch">
        {/* Header with title and last updated timestamp */}
        <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-4)">
          <Stack gap="var(--ggui-spacing-2)" align="start">
            <Heading level={1} color="var(--ggui-color-onSurface)">
              Market Watch
            </Heading>
            <Stack direction="horizontal" gap="var(--ggui-spacing-2)" align="center">
              <Badge variant={statusBadgeVariant} size="sm">
                {statusText}
              </Badge>
              {lastUpdated && (
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                  Last Updated: {lastUpdated}
                </Text>
              )}
            </Stack>
          </Stack>
        </Stack>

        {/* Grid of stock cards */}
        <Box
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(auto-fit, minmax(320px, 1fr))',
            gap: 'var(--ggui-spacing-4)',
          }}
        >
          {stocks.map((stock) => (
            <StockCard
              key={stock.symbol || 'unknown'}
              stock={stock}
              isUpdating={updatingSymbols.has(stock.symbol || '')}
            />
          ))}
        </Box>

        {/* Empty state */}
        {stocks.length === 0 && (
          <Box
            padding="var(--ggui-spacing-8)"
            background="var(--ggui-color-surfaceVariant)"
            borderRadius="var(--ggui-shape-radius-lg)"
          >
            <Stack gap="var(--ggui-spacing-2)" align="center" justify="center">
              <Icon name="trending-up" size={32} color="var(--ggui-color-onSurfaceVariant)" />
              <Text variant="body" color="var(--ggui-color-onSurfaceVariant)" align="center">
