  // Use a more comprehensive email validation pattern
  const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  // Basic format check: non-empty local part, @, domain, dot, TLD
  return emailRegex.test(email) && email.length <= 254;
};

