// Place helper components here if needed
type ProductSpecification = { key?: string; label?: string; name?: string; value?: string | number | boolean | null };
type ProductReview = { author?: string; rating?: number; text?: string; date?: string };

function coerceSpecifications(specs: unknown[] | undefined): ProductSpecification[] {
  if (!Array.isArray(specs)) return [];
  return specs
    .map((item) => {
      if (!item || typeof item !== 'object') return null;
      const spec = item as ProductSpecification;
      return spec;
    })
    .filter((item): item is ProductSpecification => item !== null);
}

function coerceReviews(reviews: unknown[] | undefined): ProductReview[] {
  if (!Array.isArray(reviews)) return [];
  return reviews
    .map((item) => {
      if (!item || typeof item !== 'object') return null;
      const review = item as ProductReview;
      return review;
    })
    .filter((item): item is ProductReview => item !== null);
}

function formatPrice(price: number | undefined, currency: string | undefined): string {
  if (typeof price !== 'number') return '—';
  const symbolMap: Record<string, string> = {
    USD: '$',
    EUR: '€',
    GBP: '£',
    JPY: '¥',
    INR: '₹',
    CAD: 'C$',
    AUD: 'A$',
    CNY: '¥',
  };
  const currencyCode = (currency || '').toUpperCase();
  const symbol = symbolMap[currencyCode] || currency || '$';
  return `${symbol}${price.toFixed(2)}`;
}

function renderStars(rating: number): string {
  const safeRating = Math.max(0, Math.min(5, Math.round(rating)));
  return `${'★'.repeat(safeRating)}${'☆'.repeat(5 - safeRating)}`;
}

