function formatCurrency(value?: number): string {
  if (typeof value !== 'number' || Number.isNaN(value)) {
    return '—';
  }
  return `$${value.toFixed(2)}`;
}

function formatSigned(value?: number): string {
  if (typeof value !== 'number' || Number.isNaN(value)) {
    return '—';
  }
  const sign = value > 0 ? '+' : value < 0 ? '' : '';
  return `${sign}${value.toFixed(2)}`;
}

function formatPercent(value?: number): string {
  if (typeof value !== 'number' || Number.isNaN(value)) {
    return '—';
  }
  const sign = value > 0 ? '+' : value < 0 ? '' : '';
  return `${sign}${value.toFixed(2)}%`;
}

function formatLastUpdated(date: Date): string {
  return date.toLocaleTimeString([], {
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });
}

export default function Component(props: Props) {
  // DO NOT EDIT wire hooks — auto-generated from the data contract

  // Streams — real-time from agent (.latest, .all)
  const priceUpdate = useStream<StreamPriceUpdate>('priceUpdate'); // Updated price data for one or more stocks
  const marketStatus = useStream<StreamMarketStatus>('marketStatus'); // Market open/closed status update

  const [stocksState, setStocksState] = useState<StockItem[]>(props.stocks ?? []);
  const [lastUpdated, setLastUpdated] = useState<Date>(new Date());
  const [flashSymbols, setFlashSymbols] = useState<Record<string, number>>({});

  useEffect(() => {
    setStocksState(props.stocks ?? []);
  }, [props.stocks]);

  useEffect(() => {
    const timer = setInterval(() => {
      setLastUpdated(new Date());
    }, 1000);

    return () => {
      clearInterval(timer);
    };
  }, []);

  useEffect(() => {
    if (!priceUpdate.latest || !priceUpdate.latest.symbol) {
      return;
    }

    const updatedSymbol = priceUpdate.latest.symbol;
    setStocksState((prev) => {
      const next = [...prev];
      const index = next.findIndex((item) => item.symbol === updatedSymbol);
      const merged: StockItem = {
        ...(index >= 0 ? next[index] : { symbol: updatedSymbol }),
        ...priceUpdate.latest,
      };

      if (index >= 0) {
        next[index] = merged;
      } else {
        next.push(merged);
      }
      return next;
    });

    setLastUpdated(new Date());
    setFlashSymbols((prev) => ({ ...prev, [updatedSymbol]: Date.now() }));
  }, [priceUpdate.latest]);

  const marketStatusText = marketStatus.latest?.status ?? 'open';

  const stockCards = useMemo(() => {
    return (stocksState ?? []).map((stock) => {
      const symbol = stock.symbol ?? 'N/A';
      const isPositive = (stock.change ?? 0) >= 0;
      const accentColor = isPositive ? 'var(--ggui-color-success-500)' : 'var(--ggui-color-error-500)';
      const arrow = isPositive ? '▲' : '▼';
      const flashAt = flashSymbols[symbol] ?? 0;
      const isFlashing = Date.now() - flashAt < 900;

      return (
        <Card
          key={symbol}
          padding="var(--ggui-spacing-4)"
          shadow="sm"
          border
          radius="lg"
        >
          <Box
            background={isFlashing ? 'var(--ggui-color-primary-50)' : 'var(--ggui-color-surface)'}
            borderRadius="var(--ggui-shape-radius-md)"
            padding="var(--ggui-spacing-3)"
          >
            <Stack gap="var(--ggui-spacing-2)">
              <Row justify="between" align="center">
                <Text
                  size="2xl"
                  weight="bold"
                  color="var(--ggui-color-onSurface)"
                >
                  {symbol}
                </Text>
                <Badge variant={isPositive ? 'success' : 'error'}>{isPositive ? 'Up' : 'Down'}</Badge>
              </Row>

              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                {stock.name ?? 'Unknown Company'}
              </Text>

              <Text size="xl" weight="semibold" color="var(--ggui-color-onSurface)">
                {formatCurrency(stock.price)}
              </Text>

              <Row gap="var(--ggui-spacing-2)" align="center">
                <Text weight="medium" color={accentColor}>
                  {formatSigned(stock.change)}
                </Text>
                <Text weight="medium" color={accentColor}>
                  {arrow} {formatPercent(stock.changePercent)}
                </Text>
              </Row>
            </Stack>
          </Box>
        </Card>
      );
    });
  }, [stocksState, flashSymbols]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-4)" shadow="sm" border radius="lg">
          <Row justify="between" align="center" wrap>
            <Stack gap="var(--ggui-spacing-1)">
              <Heading level={2} color="var(--ggui-color-onSurface)">
                Market Watch
              </Heading>
              <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                Last Updated: {formatLastUpdated(lastUpdated)}
              </Text>
            </Stack>

            <Badge
              variant={marketStatusText === 'open' ? 'success' : marketStatusText === 'closed' ? 'error' : 'warning'}
            >
              {marketStatusText}
            </Badge>
          </Row>
        </Card>

        {stockCards.length === 0 ? (
          <Alert variant="info" title="No stock data">
            No stocks are available yet. Waiting for live updates.
          </Alert>
        ) : (
          <CardGrid columns={{ sm: 1, md: 2, lg: 3 }} gap={16}>
            {stockCards}
          </CardGrid>
        )}

        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          Live updates received: {priceUpdate.all.length}
        </Text>
      </Stack>
    </Container>

  );
}

