  const handleComplete = useCallback(() => {
    if (!stepOneValid || !stepTwoValid || isSubmitting) return;
    setIsSubmitting(true);
    complete({
      name: name.trim(),
      email: email.trim(),
      avatar,
      role,
      emailNotifications,
      theme,
    });
    setIsSubmitting(false);
  }, [avatar, complete, email, emailNotifications, isSubmitting, name, role, stepOneValid, stepTwoValid, theme]);

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-6)">
        <Card padding="var(--ggui-spacing-5)" shadow="sm" border radius="lg">
          <Stack gap="var(--ggui-spacing-3)">
            <Row justify="between" align="center">
              <Heading level={3}>Onboarding Wizard</Heading>
              <Badge variant="primary">Step {step} of 3</Badge>
            </Row>
            <Progress value={progressValue} max={100} size="md" />
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)" aria-live="polite">
              {step === 1 && 'Profile Setup'}
              {step === 2 && 'Preferences'}
              {step === 3 && 'Review & Confirm'}
            </Text>
          </Stack>
        </Card>

        <Card
          padding="var(--ggui-spacing-6)"
          shadow="md"
          border
          radius="lg"
        >
          <Box
            key={step}
            style={{
              animation: 'ggui-fadeIn 200ms ease-out',
            }}
          >
            <Stack gap="var(--ggui-spacing-4)">
              {step === 1 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Profile Setup</Heading>
                  <Input
                    label="Name"
                    placeholder="Enter your name"
                    value={name}
                    onChange={setName}
                    required
                    error={!isNameValid && name.length > 0 ? 'Name is required' : ''}
                  />
                  <Input
                    label="Email"
                    type="email"
                    placeholder="you@example.com"
                    value={email}
                    onChange={setEmail}
                    required
                    error={email.length > 0 || !isEmailValid ? emailError : ''}
                  />
                  <RadioGroup
                    label="Choose an avatar"
                    value={avatar}
                    onChange={setAvatar}
                    options={normalizedAvatarOptions.map((option) => ({
                      value: option,
                      label: option,
                      description: avatar === option ? 'Selected avatar' : 'Available avatar',
                    }))}
                    direction="horizontal"
                  />
                </Stack>
              )}

              {step === 2 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Preferences</Heading>
                  <Select
                    label="Role"
                    value={role}
                    onChange={setRole}
                    options={normalizedRoleOptions.map((option) => ({ value: option, label: option }))}
                    placeholder="Select your role"
                    required
                    error={role.length === 0 ? 'Role is required' : ''}
                  />
                  <Toggle
                    label="Enable email notifications"
                    checked={emailNotifications}
                    onChange={setEmailNotifications}
                    size="md"
                  />
                  <Row align="center" justify="between">
                    <Text variant="label">Theme preference</Text>
                    <Toggle
                      label={theme === 'dark' ? 'Dark theme' : 'Light theme'}
                      checked={theme === 'dark'}
                      onChange={(checked) => setTheme(checked ? 'dark' : 'light')}
                      size="md"
                    />
                  </Row>
                  <Badge variant={theme === 'dark' ? 'info' : 'warning'}>
                    {theme === 'dark' ? 'Dark mode selected' : 'Light mode selected'}
                  </Badge>
                </Stack>
              )}

              {step === 3 && (
                <Stack gap="var(--ggui-spacing-4)">
                  <Heading level={4}>Review & Confirm</Heading>
                  <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
                    Please review your information before completing setup.
                  </Text>
                  <Card padding="var(--ggui-spacing-4)" border shadow="none" radius="md">
                    <Stack gap="var(--ggui-spacing-3)">
                      <Row align="center" gap="var(--ggui-spacing-3)">
                        <Avatar name={name || 'User'} size="lg" />
                        <Stack gap="var(--ggui-spacing-1)">
                          <Text variant="label">{name || '—'}</Text>
                          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">{email || '—'}</Text>
                        </Stack>
                      </Row>
                      <Divider margin="var(--ggui-spacing-2)" />
                      <Row justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant)">Avatar</Text>
                        <Text>{avatar}</Text>
                      </Row>
                      <Row justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant)">Role</Text>
                        <Text>{role || '—'}</Text>
                      </Row>
                      <Row justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant)">Email notifications</Text>
                        <Text>{emailNotifications ? 'On' : 'Off'}</Text>
                      </Row>
                      <Row justify="between">
                        <Text color="var(--ggui-color-onSurfaceVariant)">Theme</Text>
                        <Text>{theme}</Text>
                      </Row>
                    </Stack>
                  </Card>
                  <Alert variant="info" title="Ready to complete?">
                    Click “Complete Setup” to save your onboarding profile.
                  </Alert>
                </Stack>
              )}
            </Stack>
          </Box>

          <Divider margin="var(--ggui-spacing-5)" />

          <Row justify="between" align="center" gap="var(--ggui-spacing-3)">
            <Button variant="ghost" onClick={handleBack} disabled={step === 1}>
              Back
            </Button>
            <Row gap="var(--ggui-spacing-2)">
              {step < 3 ? (
                <Button variant="primary" onClick={handleNext} disabled={!canProceed}>
                  Next
                </Button>
              ) : (
                <>
                  <Button variant="outline" onClick={handleBack}>
                    Go Back
                  </Button>
                  <Button
                    variant="primary"
                    onClick={handleComplete}
                    disabled={!stepOneValid || !stepTwoValid || isSubmitting}
                    loading={isSubmitting}
                  >
                    Complete Setup
                  </Button>
                </>
              )}
            </Row>
          </Row>
        </Card>
      </Stack>
    </Container>

  );
}
